function checkSeatAvailability(arr)
{
  return new Promise((resolve, reject)=>
  {
    setTimeout(()=>
    {
      for(let obj of arr)
      {
        if(obj.seatsAvailable === 0 || obj.seatsRequested == null || obj.seatsAvailable == null)
        {
          reject("Rejected");
          return;
        }

        if(obj.seatsAvailable < obj.seatsRequested)
        {
          resolve("Partial");
          return;
        }
      }
      resolve("Available");

    },600);

  });
}

checkSeatAvailability([
  {seatsAvailable: 10, seatsRequested: 4 },
  {seatsAvailable: 3, seatsRequested: 7 }
])
.then(res=>console.log(res))
.catch(err=>console.log(err));




// agar dono ka result show krwana hai toh 


function checkSeatAvailability(arr) {
  return new Promise((resolve) => {

    let result = [];

    for (let obj of arr) {

      if (
        obj.seatsAvailable === 0 ||
        obj.seatsRequested == null ||
        obj.seatsAvailable == null
      ) {
        result.push("Rejected");
      }
      else if (obj.seatsAvailable < obj.seatsRequested) {
        result.push("Partial");
      }
      else {
        result.push("Available");
      }
    }

    resolve(result);

  });

  
checkSeatAvailability([
  {seatsAvailable: 10, seatsRequested: 4 },
  {seatsAvailable: 3, seatsRequested: 7 }
])
.then(res=>console.log(res))
.catch(err=>console.log(err));
}
